{
  "questions": [
    {
      "format": "multipleChoice",
      "context": "Durante uma saída, Lia escreve: “A concha está meio aberta e há bolhas saindo da água perto dela. O animal deve estar assustado.”",
      "question": "Qual revisão separa melhor os tipos de registro?",
      "options": [
        {
          "feedback": "Isso mantém uma observação do que foi percebido e trata “assustado” como uma possível explicação, não como fato visto.",
          "isCorrect": true,
          "text": "Registrar as bolhas e a concha aberta; anotar “assustado” como inferência."
        },
        {
          "feedback": "A palavra “assustado” ainda apresenta uma explicação interna do animal como se fosse observação direta.",
          "isCorrect": false,
          "text": "Escrever que o animal está assustado porque a concha ficou meio aberta."
        },
        {
          "feedback": "A pergunta é útil, mas ela não substitui o registro claro do que foi visto naquele momento.",
          "isCorrect": false,
          "text": "Trocar tudo por “Por que esse animal solta bolhas quando mexe a concha?”"
        },
        {
          "feedback": "Só medir a água deixa de fora evidências visíveis importantes, como bolhas e posição da concha.",
          "isCorrect": false,
          "text": "Apagar a frase e registrar apenas a temperatura da água."
        }
      ]
    },
    {
      "format": "fillBlank",
      "question": "Complete a relação entre registro e interpretação.",
      "template": "“Há marcas semicirculares na borda da folha” é uma observação; “algum inseto mastigou a folha” é uma [BLANK].",
      "answers": [
        "inferência"
      ],
      "distractors": [
        "pergunta",
        "medida",
        "localização"
      ],
      "feedback": "A observação fica no que dá para perceber diretamente. A inferência propõe uma explicação para as marcas, então precisa ser separada do que foi visto."
    },
    {
      "format": "selectImage",
      "question": "Qual desenho ajudaria melhor alguém a notar estruturas de um pequeno cogumelo encontrado no jardim?",
      "options": [
        {
          "feedback": "Perfeito: o desenho não precisa ser bonito, mas precisa mostrar forma, proporção, posição das partes e dúvidas a confirmar.",
          "isCorrect": true,
          "prompt": "Desenho simples de um cogumelo de lado, com chapéu, haste e lamelas rotulados; proporções aproximadas; um ponto de interrogação em uma parte difícil de ver."
        },
        {
          "feedback": "Um desenho artístico pode ser bonito, mas sem rótulos e proporções claras ele ajuda menos na observação científica.",
          "isCorrect": false,
          "prompt": "Cogumelo muito sombreado e decorativo, com fundo detalhado, sem rótulos e sem indicação das partes."
        },
        {
          "feedback": "Um símbolo genérico não registra o organismo observado; ele perde detalhes importantes de forma e posição.",
          "isCorrect": false,
          "prompt": "Ícone simples de cogumelo, simétrico e genérico, sem partes internas ou diferenças de tamanho."
        },
        {
          "feedback": "Um close visual pode chamar atenção, mas sem orientação, rótulos ou vista observada fica difícil entender a estrutura inteira.",
          "isCorrect": false,
          "prompt": "Apenas um recorte das lamelas do cogumelo, sem mostrar chapéu, haste, escala ou rótulos."
        }
      ]
    },
    {
      "format": "matchColumns",
      "pairs": [
        {
          "left": "Caderno com data, hora, local, clima e organismo observado",
          "right": "Contexto para outra pessoa entender quando e onde ocorreu a observação"
        },
        {
          "left": "Foto aberta mostrando o animal e a borda do riacho",
          "right": "Evidência visual que preserva parte do ambiente ao redor"
        },
        {
          "left": "Áudio curto de um chamado repetido, salvo sem edição",
          "right": "Registro do som original para comparação posterior"
        },
        {
          "left": "Desenho com rótulos de partes que ficaram pouco nítidas na foto",
          "right": "Representação focada em estruturas, proporções e dúvidas"
        }
      ],
      "question": "Combine cada tipo de registro com o que ele sustenta melhor."
    },
    {
      "format": "multipleChoice",
      "context": "No fim da trilha, Rafa tem um vídeo editado de 8 segundos chamado “bicho legal.mp4”. Ele lembra que era fim de tarde, mas não anotou lugar exato nem condições do ambiente.",
      "question": "Qual atitude melhora mais a evidência?",
      "options": [
        {
          "feedback": "Isso recupera contexto e preserva a fonte. Sem local, horário e arquivo original, a evidência fica bem mais fraca.",
          "isCorrect": true,
          "text": "Salvar o arquivo original e completar data, hora, local e ambiente."
        },
        {
          "feedback": "A legenda pode ajudar, mas não resolve a falta de contexto nem substitui o arquivo original.",
          "isCorrect": false,
          "text": "Colocar uma legenda chamativa e postar junto com o vídeo editado."
        },
        {
          "feedback": "A duração maior não garante evidência melhor se o registro continuar sem metadados e sem original.",
          "isCorrect": false,
          "text": "Aumentar o vídeo com câmera lenta para mostrar melhor o movimento."
        },
        {
          "feedback": "O nome do arquivo ajuda na organização, mas não registra condições nem preserva a evidência bruta.",
          "isCorrect": false,
          "text": "Renomear o vídeo com um palpite sobre a espécie observada."
        }
      ]
    },
    {
      "format": "selectImage",
      "question": "Você quer uma foto que ajude a avaliar tamanho e habitat de uma larva em uma pedra úmida. Qual enquadramento é mais útil?",
      "options": [
        {
          "feedback": "Boa escolha: a escala ajuda no tamanho e um pouco do entorno mostra o contexto do micro-habitat.",
          "isCorrect": true,
          "prompt": "Larva sobre a pedra úmida, uma régua pequena ao lado e uma faixa visível de musgo e água ao redor."
        },
        {
          "feedback": "O close pode mostrar textura, mas sem escala e contexto fica difícil avaliar tamanho e ambiente.",
          "isCorrect": false,
          "prompt": "Close extremo da larva ocupando toda a imagem, sem régua e sem mostrar a pedra ao redor."
        },
        {
          "feedback": "O ambiente aparece, mas a larva fica difícil de localizar e estudar como evidência do organismo.",
          "isCorrect": false,
          "prompt": "Foto ampla da margem do riacho, com a larva muito pequena e quase invisível na pedra."
        },
        {
          "feedback": "Fundo limpo pode destacar o corpo, mas remover o organismo do contexto perde informação sobre onde ele estava.",
          "isCorrect": false,
          "prompt": "Larva colocada sobre uma folha branca, sem pedra, água, musgo ou escala."
        }
      ]
    },
    {
      "format": "multipleChoice",
      "context": "Uma foto mostra uma abelha pousada numa flor às 10h12. Não aparece pólen no corpo nem contato com o estigma da flor.",
      "question": "Qual conclusão é mais segura?",
      "options": [
        {
          "feedback": "Exato. A imagem mostra presença e momento, mas não basta para afirmar transferência de pólen.",
          "isCorrect": true,
          "text": "A abelha estava na flor naquele horário; polinização ainda é hipótese."
        },
        {
          "feedback": "Pode ter acontecido, mas a foto não mostra a transferência de pólen necessária para sustentar essa conclusão.",
          "isCorrect": false,
          "text": "A flor foi polinizada pela abelha registrada na foto."
        },
        {
          "feedback": "A foto é uma evidência útil, só que limitada ao que aparece nela.",
          "isCorrect": false,
          "text": "A foto não serve como evidência porque falta o nome da espécie."
        },
        {
          "feedback": "Visitar flor é possível, mas dizer “coletou néctar” vai além do que a imagem permite ver.",
          "isCorrect": false,
          "text": "A abelha coletou néctar durante todo o período da manhã."
        }
      ]
    }
  ]
}

{
  "questions": [
    {
      "format": "multipleChoice",
      "context": "A team wants to learn whether a new guided setup helps small-business admins reach the moment they can actually use the product: inviting at least one teammate and creating the first shared project.",
