          "isCorrect": false,
          "prompt": "A tiny two-step diagram: 'Subscribe' arrow to 'Upgrade prompt shown' with a 'within 7 days' label."
        }
      ]
    },
    {
      "format": "matchColumns",
      "pairs": [
        {
          "left": "A conversion drop appears only for traffic from one ad partner.",
          "right": "Check traffic mix and acquisition source quality."
        },
        {
          "left": "A purchase event doubled after a mobile release, but revenue did not move.",
          "right": "Check instrumentation and event firing rules."
        },
        {
          "left": "New users from January retain better than new users from March.",
          "right": "Compare cohorts, not just the blended average."
        },
        {
          "left": "Weekend usage looks lower every week.",
          "right": "Account for seasonality before calling it a product change."
        },
        {
          "left": "A dashboard has three conflicting definitions of 'activated user.'",
          "right": "Clarify metric ownership and event definitions."
        }
      ],
      "question": "Match each analytics clue to the most useful next check."
