      ]
    },
    {
      "format": "selectImage",
      "question": "Which experiment result best supports shipping a change with healthy guardrails?",
      "options": [
        {
          "feedback": "This is the strongest ship case: the primary metric improves and the safety metrics stay within acceptable bounds.",
          "isCorrect": true,
          "prompt": "A small result card showing 'Signup completion +4%' in green, 'Refunds flat,' and 'Page speed flat.'"
